srcs/main.c (ft_check_args)<pre><code>static void ft_check_args(int argc, char **argv)
{
    int len;

    // 引数は 2 個必須 (プログラム名 + .cub)
    if (argc != 2)
        ft_error("Usage: ./cub3D &lt;map.cub&gt;");

    // ファイル名の長さ
    len = ft_strlen(argv[1]);

    // 拡張子が .cub か確認
    // - ファイル名が 5 文字未満なら NG
    //   (".cub" + 最低 1 文字)
    // - 末尾 4 文字が ".cub" でないと NG
    if (len &lt; 5
        || ft_strncmp(argv[1] + len - 4,
                      ".cub", 4) != 0)
        ft_error("Invalid file extension, expected .cub");
}
</code></pre>

srcs/main.c (ft_close_window)<pre><code>static int ft_close_window(t_game *game)
{
    // × ボタンが押されたときに呼ばれる
    ft_cleanup(game);  // メモリを全解放
    exit(0);           // プログラムを終了
    return (0);        // （届かないが warning 抑止）
}
</code></pre> <p>ft_close_window はなぜ必要？</p> <p>ウィンドウの × ボタンで閉じたとき、 この関数を呼ばないと プログラムが即終了して cleanup が走らず メモリリーク になります。 <code>mlx_hook</code> のイベント 17（DestroyNotify）で登録します。</p>

parse.c (ft_parse)<pre><code>void ft_parse(char *path, t_config *config)
{
    char  *content;
    char **lines;

    // ── 準備 ──
    // config をゼロクリア (ゴミ値を防ぐ)
    ft_bzero(config, sizeof(t_config));

    // ファイル全体を1つの文字列として読み込み
    content = ft_read_file(path);

    // 改行で分割して行の配列にする
    lines = ft_split_lines(content);
    free(content);  // 元文字列はもう不要

    if (!lines)
        ft_error("Memory allocation failed");

    // エラー時クリーンアップ用の登録
    ft_set_errctx(config, lines);

    // ── 本処理 ──
    ft_process_lines(lines, config);  // 1 行ずつ処理
    ft_validate_map(config);           // マップの検証

    // ── 後片付け ──
    ft_set_errctx(NULL, NULL);
    ft_free_lines(lines);
}
</code></pre>

raycaster.c (init_step)<pre><code>static void ft_init_step(t_game *game, t_ray *ray)
{
    // ── X 方向 ──
    // 光線が左向きか右向きか判定
    if (ray-&gt;dir.x &lt; 0)
    {
        ray-&gt;step.x = -1;           // 左に進む
        // 左の格子線までの距離
        ray-&gt;side_dist.x =
            (game-&gt;player.pos.x - ray-&gt;map_pos.x)
            * ray-&gt;delta_dist.x;
    }
    else
    {
        ray-&gt;step.x = 1;            // 右に進む
        // 右の格子線までの距離
        ray-&gt;side_dist.x =
            (ray-&gt;map_pos.x + 1.0
             - game-&gt;player.pos.x)
            * ray-&gt;delta_dist.x;
    }
    // ── Y 方向も同じ処理 ──
    if (ray-&gt;dir.y &lt; 0)
    {
        ray-&gt;step.y = -1;           // 上に進む
        ray-&gt;side_dist.y =
            (game-&gt;player.pos.y - ray-&gt;map_pos.y)
            * ray-&gt;delta_dist.y;
    }
    else
    {
        ray-&gt;step.y = 1;            // 下に進む
        ray-&gt;side_dist.y =
            (ray-&gt;map_pos.y + 1.0
             - game-&gt;player.pos.y)
            * ray-&gt;delta_dist.y;
    }
}
</code></pre>

raycaster.c (dda)<pre><code>static void ft_dda(t_game *game, t_ray *ray)
{
    int hit;

    hit = 0;  // まだ壁に当たってない
    while (!hit)
    {
        // X と Y の次の格子線、近い方に進む
        if (ray-&gt;side_dist.x &lt; ray-&gt;side_dist.y)
        {
            ray-&gt;side_dist.x += ray-&gt;delta_dist.x;
            ray-&gt;map_pos.x += ray-&gt;step.x;
            ray-&gt;side = 0;  // X 壁に当たった
        }
        else
        {
            ray-&gt;side_dist.y += ray-&gt;delta_dist.y;
            ray-&gt;map_pos.y += ray-&gt;step.y;
            ray-&gt;side = 1;  // Y 壁に当たった
        }
        // マップ外に出たら強制終了（安全策）
        if (ray-&gt;map_pos.x &lt; 0
            || ray-&gt;map_pos.x &gt;= game-&gt;config.map_w
            || ray-&gt;map_pos.y &lt; 0
            || ray-&gt;map_pos.y &gt;= game-&gt;config.map_h)
            break ;
        // そのマスが壁 '1' なら終了
        if (game-&gt;config.map
                [ray-&gt;map_pos.y]
                [ray-&gt;map_pos.x] == '1')
            hit = 1;
    }
}
</code></pre>

raycaster.c (init_ray_dir)<pre><code>static void ft_init_ray_dir(t_game *game,
                            int x, t_ray *ray)
{
    double camera_x;

    // 画面の x 座標を -1〜+1 に変換
    camera_x = 2.0 * x / (double)WIN_W - 1.0;

    // 光線の向き = 正面向き + 横向き * camera_x
    ray-&gt;dir.x = game-&gt;player.dir.x
               + game-&gt;player.plane.x * camera_x;
    ray-&gt;dir.y = game-&gt;player.dir.y
               + game-&gt;player.plane.y * camera_x;

    // 今いるマスの座標を int で取得
    ray-&gt;map_pos.x = (int)game-&gt;player.pos.x;
    ray-&gt;map_pos.y = (int)game-&gt;player.pos.y;

    // 1 マス進むのに必要な光線の長さ
    if (ray-&gt;dir.x == 0)
        ray-&gt;delta_dist.x = 1e30;  // div by 0 対策
    else
        ray-&gt;delta_dist.x = fabs(1.0 / ray-&gt;dir.x);
    if (ray-&gt;dir.y == 0)
        ray-&gt;delta_dist.y = 1e30;
    else
        ray-&gt;delta_dist.y = fabs(1.0 / ray-&gt;dir.y);
}
</code></pre>

raycaster.c (calc_wall_dist)<pre><code>static void ft_calc_wall_dist(t_game *game,
                               t_ray *ray)
{
    // 垂直距離 = 魚眼補正済みの正しい距離
    if (ray-&gt;side == 0)
    {
        // X 壁（東西）に当たった
        ray-&gt;perp_wall_dist =
            ray-&gt;side_dist.x - ray-&gt;delta_dist.x;
        ray-&gt;wall_x = game-&gt;player.pos.y
            + ray-&gt;perp_wall_dist * ray-&gt;dir.y;
    }
    else
    {
        // Y 壁（南北）に当たった
        ray-&gt;perp_wall_dist =
            ray-&gt;side_dist.y - ray-&gt;delta_dist.y;
        ray-&gt;wall_x = game-&gt;player.pos.x
            + ray-&gt;perp_wall_dist * ray-&gt;dir.x;
    }
    ray-&gt;wall_x -= floor(ray-&gt;wall_x);

    // どのテクスチャを使うか
    if (ray-&gt;side == 0 &amp;&amp; ray-&gt;dir.x &gt; 0)
        ray-&gt;tex_id = TEX_EA;  // 東
    else if (ray-&gt;side == 0 &amp;&amp; ray-&gt;dir.x &lt;= 0)
        ray-&gt;tex_id = TEX_WE;  // 西
    else if (ray-&gt;side == 1 &amp;&amp; ray-&gt;dir.y &gt; 0)
        ray-&gt;tex_id = TEX_SO;  // 南
    else
        ray-&gt;tex_id = TEX_NO;  // 北
}
</code></pre>

draw_column.c (calc_draw_params)<pre><code>static void ft_calc_draw_params(t_ray *ray,
                                 t_img *tex,
                                 t_draw *d)
{
    // 壁の高さ = 画面高さ / 距離
    // 距離が近いほど高く、遠いほど低い
    d-&gt;line_h = (int)(WIN_H / ray-&gt;perp_wall_dist);

    // 描画の上端 y
    // 画面中央を基準に、壁の高さ/2 だけ上
    d-&gt;draw_start = -d-&gt;line_h / 2 + WIN_H / 2;

    // 描画の下端 y
    d-&gt;draw_end = d-&gt;line_h / 2 + WIN_H / 2;

    // 画面外にはみ出したらクリッピング
    if (d-&gt;draw_start &lt; 0)
        d-&gt;draw_start = 0;
    if (d-&gt;draw_end &gt;= WIN_H)
        d-&gt;draw_end = WIN_H - 1;

    // テクスチャの X 座標を計算
    // wall_x は 0〜1 の小数、tex-&gt;width をかけて
    // テクスチャ上のピクセル座標にする
    d-&gt;tex_x = (int)(ray-&gt;wall_x * tex-&gt;width);

    // 壁の向きによってはテクスチャを左右反転
    // (光線の向きに合わせて表示が歪まないように)
    if (ray-&gt;side == 0 &amp;&amp; ray-&gt;dir.x &gt; 0)
        d-&gt;tex_x = tex-&gt;width - d-&gt;tex_x - 1;
    if (ray-&gt;side == 1 &amp;&amp; ray-&gt;dir.y &lt; 0)
        d-&gt;tex_x = tex-&gt;width - d-&gt;tex_x - 1;

    // テクスチャ Y 方向のステップ幅
    // 壁の高さ分描くので、テクスチャの何ピクセルずつ
    // 進むかを計算
    d-&gt;step = 1.0 * tex-&gt;height / d-&gt;line_h;

    // 最初の tex_y 位置
    // (画面クリッピングされた場合の補正を含む)
    d-&gt;tex_pos = (d-&gt;draw_start - WIN_H / 2
                  + d-&gt;line_h / 2) * d-&gt;step;
}
</code></pre>

draw_column.c (draw_column)<pre><code>void ft_draw_column(t_game *game, int x, t_ray *ray)
{
    t_draw  d;
    t_img   *tex;
    int     y;
    int     tex_y;
    int     color;

    // このレイが使うテクスチャを選択
    tex = &amp;game-&gt;tex[ray-&gt;tex_id];

    // 描画パラメータを計算
    ft_calc_draw_params(ray, tex, &amp;d);

    // ── 1. 天井部分を単色で塗る ──
    ft_draw_ceiling(game, x, d.draw_start);

    // ── 2. 壁部分をテクスチャで塗る ──
    y = d.draw_start;
    while (y &lt;= d.draw_end)
    {
        // テクスチャの Y 座標を計算
        // (float を int に変換)
        tex_y = (int)d.tex_pos;

        // クリッピング (テクスチャ範囲外を防ぐ)
        if (tex_y &gt;= tex-&gt;height)
            tex_y = tex-&gt;height - 1;

        // 次の行のため tex_pos を進める
        d.tex_pos += d.step;

        // テクスチャから色を取得
        color = ft_get_texel(tex, d.tex_x, tex_y);

        // 画面に 1 ピクセル書き込む
        ft_put_pixel(&amp;game-&gt;frame, x, y, color);
        y++;
    }

    // ── 3. 床部分を単色で塗る ──
    ft_draw_floor(game, x, d.draw_end + 1);
}
</code></pre>

draw_column.c (ceiling/floor)<pre><code>static void ft_draw_ceiling(t_game *game,
                             int x, int end)
{
    int y;

    y = 0;
    // y=0 から draw_start まで天井色で埋める
    while (y &lt; end)
    {
        ft_put_pixel(&amp;game-&gt;frame, x, y,
                     game-&gt;config.ceiling.hex);
        y++;
    }
}

static void ft_draw_floor(t_game *game,
                           int x, int start)
{
    int y;

    y = start;
    // draw_end+1 から画面下端まで床色で埋める
    while (y &lt; WIN_H)
    {
        ft_put_pixel(&amp;game-&gt;frame, x, y,
                     game-&gt;config.floor.hex);
        y++;
    }
}
</code></pre>

input.c (set_key)<pre><code>// キーに対応するフラグをセット/クリア
// val = 1 (押された) or 0 (離された)
static void ft_set_key(int keycode,
                        t_keys *keys, int val)
{
    // W キー
    if (keycode == KEY_W)
        keys-&gt;w = val;
    // A キー (左ストレイフ)
    else if (keycode == KEY_A)
        keys-&gt;a = val;
    // S キー (後退)
    else if (keycode == KEY_S)
        keys-&gt;s = val;
    // D キー (右ストレイフ)
    else if (keycode == KEY_D)
        keys-&gt;d = val;
    // ← キー (左回転)
    else if (keycode == KEY_LEFT)
        keys-&gt;left = val;
    // → キー (右回転)
    else if (keycode == KEY_RIGHT)
        keys-&gt;right = val;
}
</code></pre>

input.c (key_press)<pre><code>// キーが押されたときに呼ばれる
int ft_key_press(int keycode, t_game *game)
{
    // ESC は即終了
    if (keycode == KEY_ESC)
    {
        ft_cleanup(game);  // メモリ解放
        exit(0);
    }
    // 他のキーはフラグを 1 にセット
    ft_set_key(keycode, &amp;game-&gt;keys, 1);
    return (0);
}
</code></pre>

input.c (key_release)<pre><code>// キーが離されたときに呼ばれる
int ft_key_release(int keycode, t_game *game)
{
    // フラグを 0 にクリア
    ft_set_key(keycode, &amp;game-&gt;keys, 0);
    return (0);
}
</code></pre> <p>なぜ押下と離しを分けているか？</p> <p>「押している間、移動し続ける」 を実現するため。</p> <p>もし <code>key_press</code> の中で直接移動させると、 1 回押して 1 マス動くだけになります。</p> <p>フラグで状態を持ち、毎フレーム チェックして 動くことで、滑らかな連続移動になります。</p>

move.c (can_move)<pre><code>// 指定位置に移動可能か判定
static int ft_can_move(t_game *game,
                        double x, double y)
{
    int mx;
    int my;

    // float → int で格子座標に変換
    mx = (int)x;
    my = (int)y;

    // マップ範囲外は移動不可
    if (mx &lt; 0 || mx &gt;= game-&gt;config.map_w
        || my &lt; 0 || my &gt;= game-&gt;config.map_h)
        return (0);

    // そこが壁('1') でなければ移動可
    return (game-&gt;config.map[my][mx] != '1');
}
</code></pre>

move.c (forward_back)<pre><code>static void ft_move_forward_back(t_game *game)
{
    double nx;  // 次の X 位置
    double ny;  // 次の Y 位置

    // W: 前進
    if (game-&gt;keys.w)
    {
        // プレイヤーの向き方向に MOVE_SPEED 進む
        nx = game-&gt;player.pos.x
           + game-&gt;player.dir.x * MOVE_SPEED;
        ny = game-&gt;player.pos.y
           + game-&gt;player.dir.y * MOVE_SPEED;

        // X と Y を別々に判定
        // (角でぴったり止まらず壁沿いに動くため)
        if (ft_can_move(game, nx,
                        game-&gt;player.pos.y))
            game-&gt;player.pos.x = nx;
        if (ft_can_move(game,
                        game-&gt;player.pos.x, ny))
            game-&gt;player.pos.y = ny;
    }

    // S: 後退 (同じ処理で逆方向)
    if (game-&gt;keys.s)
    {
        nx = game-&gt;player.pos.x
           - game-&gt;player.dir.x * MOVE_SPEED;
        ny = game-&gt;player.pos.y
           - game-&gt;player.dir.y * MOVE_SPEED;
        if (ft_can_move(game, nx,
                        game-&gt;player.pos.y))
            game-&gt;player.pos.x = nx;
        if (ft_can_move(game,
                        game-&gt;player.pos.x, ny))
            game-&gt;player.pos.y = ny;
    }
}
</code></pre> <p>なぜ X と Y を別々に判定？</p> <p>一緒に判定すると、角にぴったりくっついて 動けなくなる ことがあります。</p> <p>別々に判定すると、例えば右上に動こうとして 右に壁があっても、上だけ動ける。 壁沿いにスライドできる ので操作性が良くなります。</p>

move.c (rotate)<pre><code>// 回転行列を使って向きを変える
static void ft_rotate(t_game *game, double angle)
{
    double old_dir_x;
    double old_plane_x;

    // 古い dir.x を保存
    // (dir.y の更新で dir.x を使うので)
    old_dir_x = game-&gt;player.dir.x;

    // 2D 回転行列:
    // | cos  -sin | | x |   | x*cos - y*sin |
    // | sin   cos | | y | = | x*sin + y*cos |
    game-&gt;player.dir.x =
        game-&gt;player.dir.x * cos(angle)
        - game-&gt;player.dir.y * sin(angle);
    game-&gt;player.dir.y =
        old_dir_x * sin(angle)
        + game-&gt;player.dir.y * cos(angle);

    // カメラプレーンも同じ角度で回転
    // (向きと連動して視野も回る必要がある)
    old_plane_x = game-&gt;player.plane.x;
    game-&gt;player.plane.x =
        game-&gt;player.plane.x * cos(angle)
        - game-&gt;player.plane.y * sin(angle);
    game-&gt;player.plane.y =
        old_plane_x * sin(angle)
        + game-&gt;player.plane.y * cos(angle);
}
</code></pre>

move.c (move)<pre><code>void ft_move(t_game *game)
{
    // WASD の判定
    ft_move_forward_back(game);
    ft_move_strafe(game);

    // 矢印キーの判定
    // 負の角度 = 反時計回り (左回転)
    if (game-&gt;keys.left)
        ft_rotate(game, -ROT_SPEED);
    // 正の角度 = 時計回り (右回転)
    if (game-&gt;keys.right)
        ft_rotate(game, ROT_SPEED);
}
