cleanup.c<pre><code>#ifdef __linux__

// Linux 専用: ディスプレイも解放する
static void ft_destroy_mlx(void *mlx)
{
    if (mlx)
    {
        // X11 ディスプレイを切断
        mlx_destroy_display(mlx);
        // mlx 構造体自体を解放
        free(mlx);
    }
}

#else

// macOS: mlx_destroy_display がない
static void ft_destroy_mlx(void *mlx)
{
    (void)mlx;  // 未使用引数の警告を抑制
}

#endif

// config 内のメモリを解放
static void ft_free_config(t_config *config)
{
    int i;

    // 4 つのテクスチャパスを解放
    i = 0;
    while (i &lt; 4)
    {
        if (config-&gt;tex_path[i])
            free(config-&gt;tex_path[i]);
        i++;
    }

    // マップデータ (二次元配列) を解放
    if (config-&gt;map)
    {
        i = 0;
        // 各行を解放
        while (i &lt; config-&gt;map_h)
        {
            free(config-&gt;map[i]);
            i++;
        }
        // 行ポインタ配列を解放
        free(config-&gt;map);
    }
}

// メイン cleanup 関数
// エラー時・正常終了時の両方から呼ばれる
void ft_cleanup(t_game *game)
{
    int i;

    // 4 つのテクスチャ画像を解放
    i = 0;
    while (i &lt; 4)
    {
        if (game-&gt;tex[i].ptr)
            mlx_destroy_image(game-&gt;mlx,
                              game-&gt;tex[i].ptr);
        i++;
    }

    // フレームバッファ (描画用 image) を解放
    if (game-&gt;frame.ptr)
        mlx_destroy_image(game-&gt;mlx,
                          game-&gt;frame.ptr);

    // ウィンドウを閉じる
    if (game-&gt;win)
        mlx_destroy_window(game-&gt;mlx, game-&gt;win);

    // ディスプレイ解放 (Linux のみ)
    ft_destroy_mlx(game-&gt;mlx);

    // config 内のメモリ解放
    ft_free_config(&amp;game-&gt;config);
}
</code></pre> <p><code>if (ptr)</code> のチェックが重要</p> <p>エラーで途中終了した場合、確保前のポインタは NULL（<code>ft_bzero</code> でゼロクリア済み）。</p> <p>NULL を <code>free</code> するのは C では安全ですが、 <code>mlx_destroy_*</code> は NULL でクラッシュする可能性があるので、 必ず NULL チェックしてから呼びます。</p>

